import { useState } from 'react';
import { FiPlus, FiMinus } from 'react-icons/fi';

const FAQ = () => {
  const [activeIndex, setActiveIndex] = useState(null);

  const toggleFAQ = (index) => {
    setActiveIndex(activeIndex === index ? null : index);
  };

  const faqs = [
    {
      question: "How accurate is your deepfake detection?",
      answer: "Our system achieves 99.7% accuracy in controlled tests, with a false positive rate of less than 0.3%. Real-world performance depends on factors like video quality and manipulation sophistication."
    },
    {
      question: "What file formats do you support?",
      answer: "We support all major formats: MP4, MOV, AVI for videos; JPG, PNG, WEBP for images. Maximum file size is 100MB for standard users."
    },
    {
      question: "How do you protect my uploaded files?",
      answer: "All files are encrypted in transit and at rest. We automatically delete analysis results after 24 hours unless you choose to save them."
    },
    {
      question: "Can you detect the latest generative AI content?",
      answer: "Our models are continuously updated to detect outputs from tools like DALL-E 3, Midjourney v6, and Stable Diffusion 3. We monitor emerging techniques daily."
    }
  ];

  return (
    <section className="py-20 relative overflow-hidden">
      {/* Subtle background pattern */}
      <div className="absolute inset-0 z-0 opacity-10">
        <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,')]">
        </div>
      </div>

      <div className="relative z-10 max-w-3xl mx-auto px-4">
        <h2 className="text-3xl font-bold text-center text-white mb-12">
          Frequently Asked Questions
        </h2>
        
        <div className="space-y-4 bg-gray-900/80 backdrop-blur-sm p-6 rounded-xl border border-gray-800">
          {faqs.map((faq, index) => (
            <div 
              key={index} 
              className="border-b border-gray-800 pb-4 last:border-0"
            >
              <button
                onClick={() => toggleFAQ(index)}
                className="flex justify-between items-center w-full text-left text-white hover:text-purple-400 transition-colors py-3"
              >
                <h3 className="text-lg font-medium">{faq.question}</h3>
                {activeIndex === index ? (
                  <FiMinus className="text-gray-400 shrink-0" />
                ) : (
                  <FiPlus className="text-gray-400 shrink-0" />
                )}
              </button>
              
              {activeIndex === index && (
                <div className="mt-2 text-gray-300 pl-2 pb-2 animate-fadeIn">
                  {faq.answer}
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Optional CTA */}
        <div className="mt-12 text-center">
          <p className="text-gray-400 mb-4">Still have questions?</p>
          <button className="bg-purple-600 hover:bg-purple-700 text-white px-6 py-3 rounded-lg font-medium transition-colors">
            Contact Our Team
          </button>
        </div>
      </div>
    </section>
  );
};

export default FAQ;
